INSERT INTO `oc_category_description` VALUES
(101,1,'Electronics','Smart devices and premium gadgets for work, gaming, and everyday life.','Electronics','Smart devices and premium gadgets for work, gaming, and everyday life.','electronics'),
(101,2,'Електроніка','Розумні пристрої та преміальні гаджети для роботи, ігор та повсякденного життя.','Електроніка','Розумні пристрої та преміальні гаджети для роботи, ігор та повсякденного життя.','електроніка'),
(101,3,'Электроника','Умные устройства и гаджеты премиум-класса для работы, игр и повседневной жизни.','Электроника','Умные устройства и гаджеты премиум-класса для работы, игр и повседневной жизни.','электроника'),
(102,1,'Home & Kitchen','Practical and stylish essentials to upgrade every room in your home.','Home & Kitchen','Practical and stylish essentials to upgrade every room in your home.','home-kitchen'),
(102,2,'Дім і кухня','Практичні та стильні речі, які допоможуть оновити кожну кімнату у вашому домі.','Дім і кухня','Практичні та стильні речі, які допоможуть оновити кожну кімнату у вашому домі.','домашня кухня'),
(102,3,'Дом и кухня','Практичные и стильные вещи, которые помогут обновить каждую комнату в вашем доме.','Дом и кухня','Практичные и стильные вещи, которые помогут обновить каждую комнату в вашем доме.','домашняя кухня'),
(103,1,'Fashion','Everyday wardrobe staples and premium pieces from trusted global brands.','Fashion','Everyday wardrobe staples and premium pieces from trusted global brands.','fashion'),
(103,2,'Мода','Основні речі щоденного гардеробу та преміальні речі від перевірених світових брендів.','Мода','Основні речі щоденного гардеробу та преміальні речі від перевірених світових брендів.','мода'),
(103,3,'Мода','Повседневные предметы гардероба и вещи премиум-класса от проверенных мировых брендов.','Мода','Повседневные предметы гардероба и вещи премиум-класса от проверенных мировых брендов.','мода'),
(104,1,'Sports &amp; Outdoors','&lt;p&gt;Gear and equipment for training, recovery, hiking, and outdoor adventures.&lt;/p&gt;','Sports &amp; Outdoors','Gear and equipment for training, recovery, hiking, and outdoor adventures.','sports-outdoors'),
(104,2,'Спорт','&lt;p&gt;Спорядження та обладнання для тренувань, відновлення, походів та пригод на природі.&lt;/p&gt;','Спорт та активний відпочинок','Спорядження та обладнання для тренувань, відновлення, походів та пригод на природі.','спорт на свіжому повітрі'),
(104,3,'Спорт','&lt;p&gt;Снаряжение и оборудование для тренировок, восстановления, походов и приключений на открытом воздухе.&lt;/p&gt;','Спорт и отдых на природе','Снаряжение и оборудование для тренировок, восстановления, походов и приключений на природе.','спорт на открытом воздухе'),
(105,1,'Beauty & Health','Top skincare, wellness, and personal care products for everyday routines.','Beauty & Health','Top skincare, wellness, and personal care products for everyday routines.','beauty-health'),
(105,2,'Краса та здоров\'я','Найкращі засоби догляду за шкірою, здоров\'я та особистої гігієни для щоденного використання.','Краса та здоров\'я','Найкращі засоби догляду за шкірою, здоров\'я та особистої гігієни для щоденного використання.','краса-здоров\'я'),
(105,3,'Красота и здоровье','Лучшие средства по уходу за кожей, для хорошего самочувствия и личной гигиены для повседневного использования.','Красота и здоровье','Лучшие средства по уходу за кожей, для хорошего самочувствия и личной гигиены для повседневного использования.','красота-здоровье'),
(106,1,'Toys &amp; Games','&lt;p&gt;Fun and educational products for kids, families, and hobby enthusiasts.&lt;/p&gt;','Toys &amp; Games','Fun and educational products for kids, families, and hobby enthusiasts.','toys-games'),
(106,2,'Іграшки та ігри','&lt;p&gt;Цікаві та розвиваючі товари для дітей, сімей та любителів хобі.&lt;/p&gt;','Іграшки та ігри','Цікаві та розвиваючі товари для дітей, сімей та любителів хобі.','іграшки-ігри'),
(106,3,'Игры','&lt;p&gt;Развлекательные и познавательные товары для детей, семей и любителей различных хобби.&lt;/p&gt;','Игрушки и игры','Развлекательные и познавательные товары для детей, семей и любителей различных хобби.','игрушки-игры'),
(107,1,'Books & Media','Bestselling books and media formats for learning, entertainment, and growth.','Books & Media','Bestselling books and media formats for learning, entertainment, and growth.','books-media'),
(107,2,'Книги та медіа','Найпопулярніші книги та медіаформати для навчання, розваг та розвитку.','Книги та медіа','Найпопулярніші книги та медіаформати для навчання, розваг та розвитку.','книги-медіа'),
(107,3,'Книги и медиа','Бестселлеры и медиаформаты для обучения, развлечения и личностного роста.','Книги и медиа','Бестселлеры и медиаформаты для обучения, развлечения и личностного роста.','книги-медиа'),
(108,1,'Automotive','&lt;p&gt;Car care essentials, electronics, and accessories for safer daily driving.&lt;/p&gt;','Automotive','Car care essentials, electronics, and accessories for safer daily driving.','automotive'),
(108,2,'Автомобільна промисловість','&lt;p&gt;Основні засоби догляду за автомобілем, електроніка та аксесуари для безпечнішого щоденного водіння.&lt;/p&gt;','Автомобільна промисловість','Основні засоби догляду за автомобілем, електроніка та аксесуари для безпечнішого щоденного водіння.','автомобільна'),
(108,3,'Автомобильная промышленность','&lt;p&gt;Товары первой необходимости для ухода за автомобилем, электроника и аксессуары для более безопасного вождения в повседневной жизни.&lt;/p&gt;','Автомобильная промышленность','Товары первой необходимости для ухода за автомобилем, электроника и аксессуары для более безопасного вождения в повседневной жизни.','автомобильный'),
(109,1,'Pet Supplies','Food, toys, and care products for healthy and happy dogs and cats.','Pet Supplies','Food, toys, and care products for healthy and happy dogs and cats.','pet-supplies'),
(109,2,'Зоотовари','Корм, іграшки та засоби догляду для здорових та щасливих собак і котів.','Зоотовари','Корм, іграшки та засоби догляду для здорових та щасливих собак і котів.','товари для домашніх тварин'),
(109,3,'Товары для животных','Корм, игрушки и средства по уходу за здоровыми и счастливыми собаками и кошками.','Товары для животных','Корм, игрушки и средства по уходу за здоровыми и счастливыми собаками и кошками.','товары для животных'),
