(48,'Newsletter Subscription','dockercart_newsletter','{\"name\":\"Newsletter Subscription\",\"status\":\"1\",\"title\":{\"1\":\"Stay in the Loop\",\"2\":\"\\u0411\\u0443\\u0434\\u044c\\u0442\\u0435 \\u0432 \\u043a\\u0443\\u0440\\u0441\\u0456\",\"3\":\"\\u041e\\u0441\\u0442\\u0430\\u0432\\u0430\\u0439\\u0442\\u0435\\u0441\\u044c \\u043d\\u0430 \\u0441\\u0432\\u044f\\u0437\\u0438\"},\"subtitle\":{\"1\":\"Get the latest deals, new arrivals and exclusive offers straight to your inbox.\",\"2\":\"\\u041e\\u0442\\u0440\\u0438\\u043c\\u0443\\u0439\\u0442\\u0435 \\u043e\\u0441\\u0442\\u0430\\u043d\\u043d\\u0456 \\u043f\\u0440\\u043e\\u043f\\u043e\\u0437\\u0438\\u0446\\u0456\\u0457, \\u043d\\u043e\\u0432\\u0456 \\u043d\\u0430\\u0434\\u0445\\u043e\\u0434\\u0436\\u0435\\u043d\\u043d\\u044f \\u0442\\u0430 \\u0435\\u043a\\u0441\\u043a\\u043b\\u044e\\u0437\\u0438\\u0432\\u043d\\u0456 \\u043f\\u0440\\u043e\\u043f\\u043e\\u0437\\u0438\\u0446\\u0456\\u0457 \\u043f\\u0440\\u044f\\u043c\\u043e \\u0443 \\u0441\\u0432\\u043e\\u044e \\u043f\\u043e\\u0448\\u0442\\u043e\\u0432\\u0443 \\u0441\\u043a\\u0440\\u0438\\u043d\\u044c\\u043a\\u0443.\",\"3\":\"\\u041f\\u043e\\u043b\\u0443\\u0447\\u0430\\u0439\\u0442\\u0435 \\u043b\\u0443\\u0447\\u0448\\u0438\\u0435 \\u043f\\u0440\\u0435\\u0434\\u043b\\u043e\\u0436\\u0435\\u043d\\u0438\\u044f, \\u043d\\u043e\\u0432\\u0438\\u043d\\u043a\\u0438 \\u0438 \\u044d\\u043a\\u0441\\u043a\\u043b\\u044e\\u0437\\u0438\\u0432\\u043d\\u044b\\u0435 \\u0441\\u043a\\u0438\\u0434\\u043a\\u0438 \\u043f\\u0440\\u044f\\u043c\\u043e \\u043d\\u0430 email.\"},\"placeholder\":{\"1\":\"Enter your email address\",\"2\":\"\\u0412\\u0432\\u0435\\u0434\\u0456\\u0442\\u044c \\u0441\\u0432\\u043e\\u044e \\u0430\\u0434\\u0440\\u0435\\u0441\\u0443 \\u0435\\u043b\\u0435\\u043a\\u0442\\u0440\\u043e\\u043d\\u043d\\u043e\\u0457 \\u043f\\u043e\\u0448\\u0442\\u0438\",\"3\":\"\\u0412\\u0432\\u0435\\u0434\\u0438\\u0442\\u0435 \\u0441\\u0432\\u043e\\u0439 \\u0430\\u0434\\u0440\\u0435\\u0441 \\u044d\\u043b\\u0435\\u043a\\u0442\\u0440\\u043e\\u043d\\u043d\\u043e\\u0439 \\u043f\\u043e\\u0447\\u0442\\u044b\"},\"button_text\":{\"1\":\"Subscribe\",\"2\":\"\\u041f\\u0456\\u0434\\u043f\\u0438\\u0441\\u0430\\u0442\\u0438\\u0441\\u044f\",\"3\":\"\\u041f\\u043e\\u0434\\u043f\\u0438\\u0441\\u0430\\u0442\\u044c\\u0441\\u044f\"},\"privacy_text\":{\"1\":\"By subscribing you agree to our Privacy Policy.\",\"2\":\"\\u041f\\u0456\\u0434\\u043f\\u0438\\u0441\\u0443\\u044e\\u0447\\u0438\\u0441\\u044c, \\u0432\\u0438 \\u043f\\u043e\\u0433\\u043e\\u0434\\u0436\\u0443\\u0454\\u0442\\u0435\\u0441\\u044f \\u0437 \\u043d\\u0430\\u0448\\u043e\\u044e \\u041f\\u043e\\u043b\\u0456\\u0442\\u0438\\u043a\\u043e\\u044e \\u043a\\u043e\\u043d\\u0444\\u0456\\u0434\\u0435\\u043d\\u0446\\u0456\\u0439\\u043d\\u043e\\u0441\\u0442\\u0456.\",\"3\":\"\\u041f\\u043e\\u0434\\u043f\\u0438\\u0441\\u044b\\u0432\\u0430\\u044f\\u0441\\u044c, \\u0432\\u044b \\u0441\\u043e\\u0433\\u043b\\u0430\\u0448\\u0430\\u0435\\u0442\\u0435\\u0441\\u044c \\u0441 \\u043d\\u0430\\u0448\\u0435\\u0439 \\u041f\\u043e\\u043b\\u0438\\u0442\\u0438\\u043a\\u043e\\u0439 \\u043a\\u043e\\u043d\\u0444\\u0438\\u0434\\u0435\\u043d\\u0446\\u0438\\u0430\\u043b\\u044c\\u043d\\u043e\\u0441\\u0442\\u0438.\"},\"success_text\":{\"1\":\"Thanks! You are now subscribed.\",\"2\":\"\\u0414\\u044f\\u043a\\u0443\\u0454\\u043c\\u043e! \\u0412\\u0438 \\u0442\\u0435\\u043f\\u0435\\u0440 \\u043f\\u0456\\u0434\\u043f\\u0438\\u0441\\u0430\\u043d\\u0456.\",\"3\":\"\\u0421\\u043f\\u0430\\u0441\\u0438\\u0431\\u043e! \\u0412\\u044b \\u0443\\u0441\\u043f\\u0435\\u0448\\u043d\\u043e \\u043f\\u043e\\u0434\\u043f\\u0438\\u0441\\u0430\\u043b\\u0438\\u0441\\u044c.\"},\"already_text\":{\"1\":\"You are subscribed\",\"2\":\"\\u0412\\u0438 \\u043f\\u0456\\u0434\\u043f\\u0438\\u0441\\u0430\\u043d\\u0456\",\"3\":\"\\u0412\\u044b \\u043f\\u043e\\u0434\\u043f\\u0438\\u0441\\u0430\\u043d\\u044b\"}}'),
