(50,'Store Features','dockercart_shop_features','{\"name\":\"Store Features\",\"status\":\"1\",\"features\":[{\"icon\":\"truck\",\"sort_order\":0,\"title\":{\"1\":\"Free Shipping\",\"2\":\"\\u0411\\u0435\\u0437\\u043a\\u043e\\u0448\\u0442\\u043e\\u0432\\u043d\\u0430 \\u0434\\u043e\\u0441\\u0442\\u0430\\u0432\\u043a\\u0430\",\"3\":\"\\u0411\\u0435\\u0441\\u043f\\u043b\\u0430\\u0442\\u043d\\u0430\\u044f \\u0434\\u043e\\u0441\\u0442\\u0430\\u0432\\u043a\\u0430\"},\"text\":{\"1\":\"On all orders over $49. Worldwide delivery available.\",\"2\":\"\\u0414\\u043b\\u044f \\u0432\\u0441\\u0456\\u0445 \\u0437\\u0430\\u043c\\u043e\\u0432\\u043b\\u0435\\u043d\\u044c \\u043f\\u043e\\u043d\\u0430\\u0434 49 \\u0434\\u043e\\u043b\\u0430\\u0440\\u0456\\u0432. \\u0414\\u043e\\u0441\\u0442\\u0443\\u043f\\u043d\\u0430 \\u0434\\u043e\\u0441\\u0442\\u0430\\u0432\\u043a\\u0430 \\u043f\\u043e \\u0432\\u0441\\u044c\\u043e\\u043c\\u0443 \\u0441\\u0432\\u0456\\u0442\\u0443.\",\"3\":\"\\u041d\\u0430 \\u0432\\u0441\\u0435 \\u0437\\u0430\\u043a\\u0430\\u0437\\u044b \\u0441\\u0432\\u044b\\u0448\\u0435 49 \\u0434\\u043e\\u043b\\u043b\\u0430\\u0440\\u043e\\u0432. \\u0414\\u043e\\u0441\\u0442\\u0430\\u0432\\u043a\\u0430 \\u043f\\u043e \\u0432\\u0441\\u0435\\u043c\\u0443 \\u043c\\u0438\\u0440\\u0443.\"}},{\"icon\":\"shield-check\",\"sort_order\":1,\"title\":{\"1\":\"2-Year Warranty\",\"2\":\"2-\\u0440\\u0456\\u0447\\u043d\\u0430 \\u0433\\u0430\\u0440\\u0430\\u043d\\u0442\\u0456\\u044f\",\"3\":\"\\u0413\\u0430\\u0440\\u0430\\u043d\\u0442\\u0438\\u044f 2 \\u0433\\u043e\\u0434\\u0430\"},\"text\":{\"1\":\"All products covered. No questions asked repairs.\",\"2\":\"\\u0412\\u0441\\u044f \\u043f\\u0440\\u043e\\u0434\\u0443\\u043a\\u0446\\u0456\\u044f \\u043f\\u043e\\u043a\\u0440\\u0438\\u0432\\u0430\\u0454\\u0442\\u044c\\u0441\\u044f. \\u0420\\u0435\\u043c\\u043e\\u043d\\u0442 \\u0431\\u0435\\u0437 \\u0437\\u0430\\u0439\\u0432\\u0438\\u0445 \\u043f\\u0438\\u0442\\u0430\\u043d\\u044c.\",\"3\":\"\\u0413\\u043